import 'package:flutter_riverpod/flutter_riverpod.dart'; import '../../../../core/di/injection.dart'; import '../../../auth/presentation/providers/auth_providers.dart'; import '../../domain/entities/review.dart'; import '../../domain/repositories/review_repository.dart';
final reviewRepositoryProvider=Provider<ReviewRepository>((ref)=>sl<ReviewRepository>()); final sellerReviewsProvider=StreamProvider.family<List<Review>,String>((ref,id)=>ref.watch(reviewRepositoryProvider).watchSellerReviews(sellerId:id)); final myReviewsProvider=StreamProvider<List<Review>>((ref){final user=ref.watch(currentUserProvider); if(user==null)return const Stream.empty(); return ref.watch(reviewRepositoryProvider).watchMyReviews(reviewerId:user.uid);}); final myProductReviewProvider=FutureProvider.family<Review?,String>((ref,productId){final user=ref.watch(currentUserProvider); if(user==null)return null; return ref.watch(reviewRepositoryProvider).getReview(reviewerId:user.uid,productId:productId);}); final reviewControllerProvider=StateNotifierProvider<ReviewController,ReviewControllerState>((ref)=>ReviewController(ref));
class ReviewController extends StateNotifier<ReviewControllerState>{final Ref ref; ReviewController(this.ref):super(const ReviewControllerState()); Future<void> createReview({required String sellerId,required String productId,String? chatRoomId,required ReviewRating rating,required String comment}) async{final user=ref.read(currentUserProvider); if(user==null){state=state.failure('Login required');return;} state=state.loading(); try{await ref.read(reviewRepositoryProvider).createReview(reviewerId:user.uid,sellerId:sellerId,productId:productId,chatRoomId:chatRoomId,rating:rating,comment:comment); ref.invalidate(sellerReviewsProvider(sellerId)); ref.invalidate(myProductReviewProvider(productId)); state=state.successState();}catch(e){state=state.failure(e.toString());}} Future<void> updateReview({required String reviewId,required String sellerId,required String productId,required ReviewRating rating,required String comment}) async{state=state.loading(); try{await ref.read(reviewRepositoryProvider).updateReview(reviewId:reviewId,rating:rating,comment:comment); ref.invalidate(sellerReviewsProvider(sellerId)); ref.invalidate(myProductReviewProvider(productId)); state=state.successState();}catch(e){state=state.failure(e.toString());}} Future<void> deleteReview({required String reviewId,required String sellerId,required String productId}) async{await ref.read(reviewRepositoryProvider).deleteReview(reviewId:reviewId); ref.invalidate(sellerReviewsProvider(sellerId)); ref.invalidate(myProductReviewProvider(productId));}}
class ReviewControllerState{final bool isLoading,success; final String? errorMessage; const ReviewControllerState({this.isLoading=false,this.success=false,this.errorMessage}); ReviewControllerState loading()=>const ReviewControllerState(isLoading:true); ReviewControllerState successState()=>const ReviewControllerState(success:true); ReviewControllerState failure(String m)=>ReviewControllerState(errorMessage:m);}
